class Solution:
    def absDifference(self, nums, k):
        remaining = list(nums)
        top = 0
        for _ in range(k):
            m = max(remaining)
            top += m
            remaining.remove(m)
        remaining = list(nums)
        bot = 0
        for _ in range(k):
            m = min(remaining)
            bot += m
            remaining.remove(m)
        return abs(top - bot)

