var absDifference = function(nums, k) {
    const s = [...nums].sort((a, b) => a - b);
    let top = 0;
    for (let i = s.length - k; i < s.length; i++) top += s[i];
    let bot = 0;
    for (let i = 0; i < k; i++) bot += s[i];
    return Math.abs(top - bot);
};
